import Link from "next/link";
import { redirect } from "next/navigation";

import { SearchBar } from "@/components/SearchBar";
import { getSession } from "@/lib/auth/session";
import {
  getDistributor,
  getOutstandingForRetailer,
  getRetailer,
  listOffers,
} from "@/lib/db/store";
import { paiseToRupees } from "@/lib/types";

export const dynamic = "force-dynamic";

const QUICK_LINKS = [
  { href: "/dashboard/distributors", label: "Distributors", icon: "shop", description: "Browse all suppliers" },
  { href: "/dashboard/schemes", label: "Schemes", icon: "tag", description: "Active deals" },
  { href: "/dashboard/generics", label: "Generic medicines", icon: "pills", description: "Substitute by generic" },
  { href: "/dashboard/scan", label: "Scan prescription", icon: "scan", description: "Photo to medicines" },
  { href: "/dashboard/profile", label: "Outstanding payments", icon: "rupee", description: "Per-distributor balance" },
];

export default function HomePage() {
  const session = getSession();
  if (!session) redirect("/");
  const retailer = getRetailer(session.retailerId);
  if (!retailer) redirect("/");

  const offers = listOffers().map((o) => ({
    ...o,
    distributorName: getDistributor(o.distributorId)?.name ?? "Unknown distributor",
  }));
  const outstanding = getOutstandingForRetailer(session.retailerId).map((p) => ({
    ...p,
    distributorName: getDistributor(p.distributorId)?.name ?? "Unknown distributor",
  }));
  const outstandingTotal = outstanding.reduce((acc, p) => acc + p.amountDuePaise, 0);

  return (
    <div className="space-y-6 px-4 pb-6 pt-6">
      <header>
        <p className="text-sm text-slate-500">Welcome back,</p>
        <h1 className="text-2xl font-semibold text-slate-900">{retailer.ownerName.split(" ")[0]}</h1>
        <p className="mt-1 text-sm text-slate-500">{retailer.storeName}</p>
      </header>

      <SearchBar />

      <section aria-labelledby="offers-heading">
        <div className="flex items-baseline justify-between">
          <h2 id="offers-heading" className="text-sm font-semibold uppercase tracking-wider text-slate-600">
            Offers
          </h2>
          <span className="text-xs text-slate-400">{offers.length} active</span>
        </div>
        <div className="-mx-4 mt-3 overflow-x-auto px-4">
          <ul className="flex snap-x snap-mandatory gap-3">
            {offers.map((o) => (
              <li
                key={o.id}
                className="snap-start rounded-2xl bg-gradient-to-br from-brand-600 to-brand-900 p-4 text-white shadow-md min-w-[280px] max-w-[280px]"
              >
                <p className="inline-flex rounded-full bg-white/20 px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wider">
                  {o.bannerLabel}
                </p>
                <h3 className="mt-2 text-base font-semibold leading-tight">{o.title}</h3>
                <p className="mt-1 line-clamp-2 text-sm text-white/80">{o.description}</p>
                <p className="mt-3 text-xs text-white/70">By {o.distributorName}</p>
              </li>
            ))}
          </ul>
        </div>
      </section>

      <section aria-labelledby="quick-links-heading">
        <h2 id="quick-links-heading" className="text-sm font-semibold uppercase tracking-wider text-slate-600">
          Quick links
        </h2>
        <ul className="mt-3 grid grid-cols-2 gap-3">
          {QUICK_LINKS.map((q) => (
            <li key={q.href}>
              <Link
                href={q.href}
                className="flex h-full flex-col rounded-2xl border border-slate-200 bg-white p-4 shadow-sm transition hover:border-brand-300 hover:shadow-md"
              >
                <span className="flex h-9 w-9 items-center justify-center rounded-full bg-brand-50 text-brand-600">
                  <QuickLinkIcon name={q.icon} />
                </span>
                <p className="mt-2 text-sm font-semibold text-slate-900">{q.label}</p>
                <p className="mt-0.5 text-xs text-slate-500">{q.description}</p>
              </Link>
            </li>
          ))}
        </ul>
      </section>

      <section aria-labelledby="outstanding-heading" className="rounded-2xl border border-amber-200 bg-amber-50 p-4">
        <div className="flex items-center justify-between">
          <h2 id="outstanding-heading" className="text-sm font-semibold uppercase tracking-wider text-amber-900">
            Outstanding payments
          </h2>
          <Link href="/dashboard/profile" className="text-xs font-medium text-amber-900 underline-offset-2 hover:underline">
            View all
          </Link>
        </div>
        <p className="mt-2 text-3xl font-bold text-amber-900">{paiseToRupees(outstandingTotal)}</p>
        <ul className="mt-3 space-y-1.5 text-sm text-amber-900">
          {outstanding.map((p) => (
            <li key={p.id} className="flex items-baseline justify-between">
              <span>{p.distributorName}</span>
              <span className="font-semibold">{paiseToRupees(p.amountDuePaise)}</span>
            </li>
          ))}
          {outstanding.length === 0 ? (
            <li className="text-sm text-amber-900">No outstanding balance.</li>
          ) : null}
        </ul>
      </section>
    </div>
  );
}

function QuickLinkIcon({ name }: { name: string }) {
  const common = {
    width: 18,
    height: 18,
    viewBox: "0 0 24 24",
    fill: "none",
    stroke: "currentColor",
    strokeWidth: 1.8,
    strokeLinecap: "round" as const,
    strokeLinejoin: "round" as const,
  };
  if (name === "shop") {
    return (
      <svg {...common}>
        <path d="M3 9h18l-1 11H4L3 9Z" />
        <path d="M3 9 5 4h14l2 5" />
      </svg>
    );
  }
  if (name === "tag") {
    return (
      <svg {...common}>
        <path d="M20 12 12 20l-9-9V3h8l9 9Z" />
        <circle cx="7.5" cy="7.5" r="1.2" />
      </svg>
    );
  }
  if (name === "pills") {
    return (
      <svg {...common}>
        <rect x="3" y="9" width="10" height="6" rx="3" />
        <circle cx="17" cy="15" r="4" />
        <path d="M14 15h6" />
      </svg>
    );
  }
  if (name === "scan") {
    return (
      <svg {...common}>
        <path d="M4 8V5a1 1 0 0 1 1-1h3" />
        <path d="M16 4h3a1 1 0 0 1 1 1v3" />
        <path d="M20 16v3a1 1 0 0 1-1 1h-3" />
        <path d="M8 20H5a1 1 0 0 1-1-1v-3" />
        <path d="M8 12h8" />
      </svg>
    );
  }
  return (
    <svg {...common}>
      <path d="M7 5h10" />
      <path d="M7 9h10" />
      <path d="M7 9c2.6 0 4 1.5 4 4 0 2.4-1.4 4-4 4l4 4" />
    </svg>
  );
}

import Link from "next/link";
import { redirect } from "next/navigation";

import { MedicineRow } from "@/components/MedicineRow";
import { SearchBar } from "@/components/SearchBar";
import { getSession } from "@/lib/auth/session";
import { getDistributor, searchMedicines } from "@/lib/db/store";

export const dynamic = "force-dynamic";

interface SearchPageProps {
  searchParams: { q?: string };
}

export default function SearchPage({ searchParams }: SearchPageProps) {
  const session = getSession();
  if (!session) redirect("/");
  const q = (searchParams.q ?? "").trim();
  const meds = searchMedicines(q).slice(0, 50);

  return (
    <div className="space-y-4 px-4 pb-6 pt-6">
      <header className="flex items-center gap-3">
        <Link
          href="/dashboard/home"
          className="text-sm font-medium text-brand-600 hover:underline"
          aria-label="Back to home"
        >
          &larr; Home
        </Link>
        <h1 className="text-lg font-semibold text-slate-900">
          {q ? `Results for "${q}"` : "All medicines"}
        </h1>
      </header>

      <SearchBar initialQuery={q} />

      <p className="text-xs text-slate-500">
        Showing {meds.length} {meds.length === 1 ? "medicine" : "medicines"}
        {meds.length === 50 ? " (capped)" : ""}.
      </p>

      <ul className="space-y-3">
        {meds.map((m) => (
          <li key={m.id}>
            <MedicineRow
              id={m.id}
              name={m.name}
              brand={m.brand}
              genericName={m.genericName}
              distributorName={getDistributor(m.distributorId)?.name ?? "Unknown distributor"}
              mrpPaise={m.mrpPaise}
              sellingPricePaise={m.sellingPricePaise}
              scheme={m.scheme}
              packSize={m.packSize}
            />
          </li>
        ))}
        {meds.length === 0 ? (
          <li className="rounded-2xl border border-dashed border-slate-300 bg-white p-6 text-center text-sm text-slate-500">
            No medicines matched &ldquo;{q}&rdquo;. Try a brand or a generic name.
          </li>
        ) : null}
      </ul>
    </div>
  );
}

"use client";

import { useState, useTransition } from "react";

import { paiseToRupees } from "@/lib/types";

export interface MedicineRowProps {
  id: string;
  name: string;
  brand: string;
  genericName: string;
  distributorName: string;
  mrpPaise: number;
  sellingPricePaise: number;
  scheme: string | null;
  packSize: string;
}

export function MedicineRow(props: MedicineRowProps) {
  const [isPending, startTransition] = useTransition();
  const [added, setAdded] = useState(false);
  const [error, setError] = useState<string | null>(null);

  function onAdd() {
    setError(null);
    startTransition(async () => {
      try {
        const res = await fetch("/api/cart/items", {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ medicineId: props.id, qty: 1 }),
        });
        if (!res.ok) {
          const body = (await res.json().catch(() => ({}))) as { error?: string };
          setError(body.error ?? `Add to cart failed (${res.status})`);
          return;
        }
        setAdded(true);
        setTimeout(() => setAdded(false), 1500);
      } catch (e) {
        setError((e as Error).message);
      }
    });
  }

  const discountPct =
    props.mrpPaise > props.sellingPricePaise
      ? Math.round(((props.mrpPaise - props.sellingPricePaise) / props.mrpPaise) * 100)
      : 0;

  return (
    <article className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
      <div className="flex items-start justify-between gap-3">
        <div className="min-w-0">
          <h3 className="truncate text-base font-semibold text-slate-900">{props.name}</h3>
          <p className="truncate text-sm text-slate-600">
            {props.brand}
            <span className="text-slate-400"> &middot; </span>
            {props.genericName}
          </p>
          <p className="mt-1 text-xs text-slate-500">
            {props.distributorName}
            <span className="text-slate-400"> &middot; </span>
            {props.packSize}
          </p>
        </div>
        <div className="text-right">
          <p className="text-base font-semibold text-slate-900">{paiseToRupees(props.sellingPricePaise)}</p>
          {discountPct > 0 ? (
            <p className="text-xs text-slate-500">
              <span className="line-through">{paiseToRupees(props.mrpPaise)}</span>
              <span className="ml-1 font-medium text-emerald-600">{discountPct}% off</span>
            </p>
          ) : null}
        </div>
      </div>

      {props.scheme ? (
        <p className="mt-2 inline-flex rounded-full bg-amber-100 px-2 py-0.5 text-xs font-medium text-amber-800">
          Scheme: {props.scheme}
        </p>
      ) : null}

      <div className="mt-3 flex items-center justify-end gap-2">
        {error ? <span className="text-xs text-red-600">{error}</span> : null}
        <button
          type="button"
          onClick={onAdd}
          disabled={isPending || added}
          className="rounded-xl bg-brand-600 px-4 py-2 text-sm font-semibold text-white transition hover:bg-brand-700 disabled:cursor-not-allowed disabled:opacity-60"
        >
          {added ? "Added" : isPending ? "Adding..." : "Add to cart"}
        </button>
      </div>
    </article>
  );
}

"use client";

import { useRouter } from "next/navigation";
import { useState } from "react";

export function SearchBar({ initialQuery = "" }: { initialQuery?: string }) {
  const router = useRouter();
  const [q, setQ] = useState(initialQuery);

  function onSubmit(event: React.FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const term = q.trim();
    router.push(term ? `/dashboard/search?q=${encodeURIComponent(term)}` : "/dashboard/search");
  }

  return (
    <form onSubmit={onSubmit} role="search" className="relative">
      <span className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <circle cx="11" cy="11" r="7" />
          <path d="m20 20-3.5-3.5" strokeLinecap="round" />
        </svg>
      </span>
      <input
        type="search"
        name="q"
        value={q}
        onChange={(e) => setQ(e.target.value)}
        placeholder="Search medicines, brand, or generic..."
        autoComplete="off"
        className="w-full rounded-2xl border border-slate-200 bg-white py-3 pl-10 pr-4 text-base text-slate-900 placeholder:text-slate-400 shadow-sm focus:border-brand-500 focus:outline-none focus:ring-2 focus:ring-brand-500/30"
        aria-label="Search medicines"
      />
    </form>
  );
}

